```python
p = 10**9 + 7
import math

def inv(k, mod):
    return pow(k, mod - 2, mod)

n = int(input())
if n == 1:
    print(1)
    exit()
if n == 2:
    print(1)
    exit()

max_k = 0
while (1 << (max_k + 1)) <= n:
    max_k += 1

facs = [1] * (n + 1)
for i in range(2, n + 1):
    facs[i] = (i * facs[i - 1]) % p

inv_facs = [1] * (n + 1)
inv_facs[n] = inv(facs[n], p)
for i in range(n - 1, -1, -1):
    inv_facs[i] = (inv_facs[i + 1] * (i + 1)) % p

def comb(a, b):
    if a < 0 or b < 0 or a < b:
        return 0
    return facs[a] * inv_facs[b] % p * inv_facs[a - b] % p

m = 1 << max_k
if m // 2 * 3 <= n:
    m = m // 2 * 3

res = facs[m - 1] * facs[n - m + 1] % p
res = res * comb(n, m - 1) % p
print(res)
